import { useState, useEffect } from "react";
import Login from "./pages/Login";
import IssueSelect from "./pages/IssueSelect";
import Chat from "./pages/Chat";
import AgentDashboard from "./pages/AgentDashboard";
import { doc, getDoc } from "firebase/firestore";
import { db } from "./firebase";

export default function App() {
  const [user, setUser] = useState(null);
  const [role, setRole] = useState(null);
  const [sessionId, setSessionId] = useState(null);

  useEffect(() => {
    if (user) {
      getDoc(doc(db, "users", user.uid)).then(d => setRole(d.data().role));
    }
  }, [user]);

  if (!user) return <Login setUser={setUser} />;

  if (role === "customer") {
    if (!sessionId) return <IssueSelect user={user} setSessionId={setSessionId} />;
    return <Chat sessionId={sessionId} user={user} />;
  }

  if (role === "agent") {
    return <AgentDashboard user={user} />;
  }

  return null;
}
